use std::collections::VecDeque;

struct MessageBuffer {
    data: Vec<u8>,
    head_index: usize,
    tail_capacity: usize,
}

impl MessageBuffer {
    fn new(initial_data: Vec<u8>, capacity: usize) -> Self {
        MessageBuffer {
            data: initial_data,
            head_index: 0,
            tail_capacity: capacity
        }
    }

    fn add_message(&mut self, message: &[u8]) -> Result<(), &'static str> {
        if self.data.len() < self.tail_capacity {
            self.data.extend_from_slice(message);
            println!("Successfully added data chunk.");
            Ok(())
        } else {
            Err("Buffer is full, cannot write more data safely.")
        }
    }

    fn retrieve_next(&mut self) -> Option<&[u8]> {
        if self.head_index < self.data.len() - self.tail_capacity + 1 {
            let start = self.head_index;
            let end = (self.head_index + self.tail_capacity).min(self.data.len());
            let chunk = &self.data[start..end];
            self.head_index += self.tail_capacity;
            Some(chunk)
        } else {
            None
        }
    }
}

fn main() {
    let initial_bytes: Vec<u8> = vec![0xde, 0xad, 0xbe, 0xef];
    let mut buffer = MessageBuffer::new(initial_bytes, 12);

    if buffer.add_message(&[0xca, 0xfe]).is_ok() {
        println!("Attempting to retrieve messages...");
        loop {
            match buffer.retrieve_next() {
                Some(chunk) => println!("Retrieved chunk: {:?}", chunk),
                None => break,
            }
        }
    }
}
